#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const LL &x){if(x>9ll)print(x/10ll);putchar(x%10ll+'0');}
const int N=1e6+10;LL phi[N];int pm[N>>2],cpt;bool vs[N];
inline void Init(const int &mxn)
{
	phi[1]=1;vs[1]=true;rep(2,mxn,i)
	{
		if(!vs[i])phi[pm[++cpt]=i]=i-1;for(int j=1;j<=cpt&&pm[j]*i<=mxn;++j)
		{
			vs[pm[j]*i]=true;if(i%pm[j]==0){phi[pm[j]*i]=phi[i]*pm[j];break;}
			phi[pm[j]*i]=phi[i]*(pm[j]-1);
		}
	}
	rep(1,mxn,i)phi[i]=phi[i]*i/2;
}
int main()
{
	int T=read();Init(T<=5?100000:1000000);
	while(T--)
	{
		int x=read();if(x==1){putchar('1');putchar('\n');continue;}LL res=phi[1]+phi[x];
		for(int j=2;j*j<=x;++j)if(x%j==0){res+=phi[j];if(j!=x/j)res+=phi[x/j];}print((res+1)*x);putchar('\n');
	}
}
